import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { LogIn, Mail, Lock, LogOut, ShieldCheck, FileText, Activity, UserPlus, Menu, X } from 'lucide-react';

const Login = () => {
  const [isRegistering, setIsRegistering] = useState(false);
  const [formData, setFormData] = useState({ name: '', email: '', password: '' });
  const [message, setMessage] = useState('');
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [activeView, setActiveView] = useState('Overview');

  useEffect(() => {
    const token = localStorage.getItem('token');
    if (token) setIsLoggedIn(true);
  }, []);

  const handleAuth = async (e) => {
    e.preventDefault();
    const url = isRegistering ? 'register' : 'login';
    try {
      const res = await axios.post(`http://localhost:5000/api/auth/${url}`, formData);
      if (!isRegistering) {
        localStorage.setItem('token', res.data.token);
        localStorage.setItem('userName', res.data.user.name);
        setIsLoggedIn(true);
      } else {
        setMessage('✅ Registered! Please login.');
        setIsRegistering(false);
      }
    } catch (err) {
      setMessage(err.response?.data?.msg || 'Action Failed');
    }
  };

  const handleLogout = () => {
    localStorage.clear();
    setIsLoggedIn(false);
  };

  if (isLoggedIn) {
    return (
      <div className="min-h-screen bg-gray-50 flex flex-col">
        {/* Responsive Navbar */}
        <nav className="bg-white shadow-sm border-b border-gray-200 p-4 sticky top-0 z-50">
          <div className="max-w-7xl mx-auto flex justify-between items-center">
            <h1 className="text-xl font-extrabold text-blue-600 tracking-tight">QUAD<span className="text-gray-800">SOLUTIONS</span></h1>
            <button onClick={handleLogout} className="text-red-500 flex items-center gap-1 font-semibold text-sm md:text-base">
              <LogOut size={18} /> <span className="hidden sm:inline">Logout</span>
            </button>
          </div>
        </nav>

        {/* Responsive Main Content */}
        <main className="p-4 md:p-8 max-w-7xl mx-auto w-full">
          <div className="mb-8">
            <h2 className="text-2xl font-bold text-gray-800">Welcome, {localStorage.getItem('userName')}</h2>
            <p className="text-gray-500">Your professional credentialing overview</p>
          </div>

          {/* GRID: 1 column on mobile, 3 columns on medium screens+ */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 md:gap-6">
            <div onClick={() => setActiveView('Licenses')} className="bg-white p-6 rounded-2xl shadow-sm border-b-4 border-blue-500 cursor-pointer active:scale-95 transition">
              <ShieldCheck className="text-blue-500 mb-2" size={28} />
              <h3 className="text-gray-500 text-sm font-medium">Active Licenses</h3>
              <p className="text-2xl font-bold">04</p>
            </div>
            
            <div onClick={() => setActiveView('Certifications')} className="bg-white p-6 rounded-2xl shadow-sm border-b-4 border-green-500 cursor-pointer active:scale-95 transition">
              <FileText className="text-green-500 mb-2" size={28} />
              <h3 className="text-gray-500 text-sm font-medium">Certifications</h3>
              <p className="text-2xl font-bold">12</p>
            </div>

            <div onClick={() => setActiveView('Compliance')} className="bg-white p-6 rounded-2xl shadow-sm border-b-4 border-orange-500 cursor-pointer active:scale-95 transition">
              <Activity className="text-orange-500 mb-2" size={28} />
              <h3 className="text-gray-500 text-sm font-medium">Profile Status</h3>
              <p className="text-2xl font-bold text-green-600">92%</p>
            </div>
          </div>

          {/* Detailed Section */}
          <div className="mt-8 bg-white p-6 rounded-2xl border border-gray-200 shadow-sm">
             <h3 className="text-lg font-bold text-gray-800 mb-4">Detailed View: {activeView}</h3>
             <div className="h-32 flex items-center justify-center border-2 border-dashed border-gray-100 rounded-xl">
                <p className="text-gray-400 text-sm italic">Loading specific documents for {activeView}...</p>
             </div>
          </div>
        </main>
      </div>
    );
  }

  return (
    <div className="flex items-center justify-center min-h-screen bg-slate-100 p-4">
      <div className="w-full max-w-md bg-white p-8 rounded-3xl shadow-xl border-t-8 border-blue-600">
        <div className="text-center mb-8">
          <div className="inline-block p-4 bg-blue-50 rounded-full text-blue-600 mb-4">
            {isRegistering ? <UserPlus size={32} /> : <LogIn size={32} />}
          </div>
          <h2 className="text-3xl font-black text-gray-900">{isRegistering ? "Join Us" : "Provider Login"}</h2>
          <p className="text-gray-500 mt-2">QuadSolutions Credentialing Portal</p>
        </div>

        <form onSubmit={handleAuth} className="space-y-4">
          {isRegistering && (
            <input type="text" placeholder="Full Name" className="w-full px-4 py-3 rounded-xl bg-gray-50 border-transparent focus:bg-white focus:border-blue-500 focus:ring-0 transition"
              onChange={(e) => setFormData({...formData, name: e.target.value})} required />
          )}
          <input type="email" placeholder="Email Address" className="w-full px-4 py-3 rounded-xl bg-gray-50 border-transparent focus:bg-white focus:border-blue-500 focus:ring-0 transition"
            onChange={(e) => setFormData({...formData, email: e.target.value})} required />
          <input type="password" placeholder="Password" className="w-full px-4 py-3 rounded-xl bg-gray-50 border-transparent focus:bg-white focus:border-blue-500 focus:ring-0 transition"
            onChange={(e) => setFormData({...formData, password: e.target.value})} required />
          
          <button className="w-full bg-blue-600 py-4 rounded-xl text-white font-bold text-lg hover:bg-blue-700 shadow-lg shadow-blue-200 transition">
            {isRegistering ? "Create Account" : "Sign In"}
          </button>
        </form>

        <button onClick={() => setIsRegistering(!isRegistering)} className="w-full mt-6 text-sm font-bold text-gray-400 hover:text-blue-600 transition">
          {isRegistering ? "Already have an account? Login" : "Don't have an account? Register"}
        </button>

        {message && <p className="mt-4 text-center text-red-500 font-semibold">{message}</p>}
      </div>
    </div>
  );
};

export default Login;
